css:
.loader {color: var(--loader-color, #b45309);
  --loader-secondary-color: #fcd34d;
  --loader-bg: #ffffff;
   width: 18px;
   aspect-ratio: 1;
   background: var(--loader-color, #b45309);
   animation: l7-1 1s infinite alternate, l7-2 2s infinite alternate;
}
@keyframes l7-1  {
  0%,10%{transform:scale(1) rotate(0)}
100% {transform:scale(0) rotate(1turn)}
}
@keyframes l7-2  {
  0%,49.99% {background:var(--loader-color, #b45309)}
50%,100% {background:var(--loader-secondary-color, #fcd34d)}
}
